const manifest = $json.manifest || {};
const runtime = $json.runtime || {};
const baseScenarios = Array.isArray(manifest.base_item_scenarios) ? manifest.base_item_scenarios : [];
const families = [
  { family_key: 'afiliados', family_label: 'Afiliados' },
  { family_key: 'rede', family_label: 'Rede' },
];

function normalizeScenario(baseScenario) {
  const scenarioId = String(baseScenario.scenario_id || '');
  const scenarioSeq = Number(String(scenarioId).replace(/^S/, '')) || 0;
  const values = (baseScenario.values && typeof baseScenario.values === 'object' && !Array.isArray(baseScenario.values))
    ? baseScenario.values
    : {};
  const currencyKey = String(values.moeda_da_fatura || '').startsWith('USD') ? 'usd' : 'brl';
  const currencyCode = currencyKey.toUpperCase();
  const itemTypeKey = values.tipo_de_item === 'Ajustes de fatura' ? 'ajuste' : 'produto';
  const itemTypeLabel = itemTypeKey === 'ajuste' ? 'Ajuste' : 'Produto';
  return {
    source_scenario_id: scenarioId,
    scenario_seq: scenarioSeq,
    scenario_seq_pad: String(scenarioSeq).padStart(3, '0'),
    currency_key: currencyKey,
    currency_code: currencyCode,
    item_type_key: itemTypeKey,
    item_type_label: itemTypeLabel,
    values,
    visible_fields: Array.isArray(baseScenario.visible_fields) ? baseScenario.visible_fields : [],
  };
}

const normalized = baseScenarios.map(normalizeScenario);
const batches = [];
for (const family of families) {
  for (const currencyKey of ['brl', 'usd']) {
    const adjustments = normalized
      .filter((scenario) => scenario.currency_key === currencyKey && scenario.item_type_key === 'ajuste')
      .map((scenario) => ({
        ...scenario,
        family_key: family.family_key,
        family_label: family.family_label,
        item_spec_id: `${family.family_key}_${currencyKey}_${scenario.source_scenario_id}`,
      }));
    const products = normalized
      .filter((scenario) => scenario.currency_key === currencyKey && scenario.item_type_key === 'produto')
      .map((scenario) => ({
        ...scenario,
        family_key: family.family_key,
        family_label: family.family_label,
        item_spec_id: `${family.family_key}_${currencyKey}_${scenario.source_scenario_id}`,
      }));

    let batchSeq = 0;
    while (adjustments.length > 0 || products.length > 0) {
      batchSeq += 1;
      const itemSpecs = adjustments.splice(0, 2).concat(products.splice(0, 3));
      batches.push({
        batch_key: `${family.family_key}_${currencyKey}_b${String(batchSeq).padStart(3, '0')}`,
        batch_seq: batchSeq,
        batch_seq_pad: String(batchSeq).padStart(3, '0'),
        family_key: family.family_key,
        family_label: family.family_label,
        currency_key: currencyKey,
        currency_code: currencyKey.toUpperCase(),
        rule_template_key: `${family.family_key}_${currencyKey}`,
        item_specs: itemSpecs,
      });
    }
  }
}

return batches.map((batch) => ({ json: { runtime, batch } }));

const sd = $getWorkflowStaticData('global');
const manifest = sd.finSeedManifest || {};
const runtime = $json.runtime || {};
const batch = $json.batch || {};
const defaults = (manifest.defaults && manifest.defaults.fin02) ? manifest.defaults.fin02 : {};
const coercion = (manifest.coercion && typeof manifest.coercion === 'object') ? manifest.coercion : {};
const arrayFields = new Set(Array.isArray(coercion.fin02_array_fields) ? coercion.fin02_array_fields : []);
const numberFields = new Set(Array.isArray(coercion.fin02_number_fields) ? coercion.fin02_number_fields : []);
const percentLikeFields = new Set([
  'percentual_a_ser_aplicado_na_base',
  'percentual_de_desconto_a_ser_aplicado',
  'desconto_no_valor_vari_vel_do_saas_para_a_b',
  'desconto_no_valor_vari_vel_do_saas_para_e_s',
  'desconto_no_valor_vari_vel_do_saas_para_hospedagem',
  'desconto_no_valor_vari_vel_do_saas_para_espa_os',
  'desconto_no_valor_vari_vel_do_saas_para_outros',
]);
const noopDateField = 'data_de_fim_do_faturamento';

function isBlank(value) {
  if (value === undefined || value === null) return true;
  if (typeof value === 'string') return value.trim() === '';
  if (Array.isArray(value)) return value.length === 0;
  return false;
}

function toArray(value) {
  if (Array.isArray(value)) return value.map((entry) => String(entry));
  return [String(value)];
}

function coerceValue(fieldId, value) {
  if (arrayFields.has(fieldId)) return toArray(value);
  if (numberFields.has(fieldId)) return Number(value);
  return String(value);
}

function buildFields(spec) {
  const values = JSON.parse(JSON.stringify(spec.values || {}));
  const visible = new Set(Array.isArray(spec.visible_fields) ? spec.visible_fields : []);
  const currencyKey = String(spec.currency_key || '').toLowerCase();
  const activeSubtotalField = currencyKey === 'usd' ? 'subtotal_do_item_usd' : 'subtotal_do_item_brl';
  const activeTotalField = currencyKey === 'usd' ? 'valor_total_do_item_com_descontos_usd' : 'valor_total_do_item_com_descontos_brl';
  const activeUnitField = currencyKey === 'usd' ? 'valor_unit_rio_usd' : 'valor_unit_rio_brl';
  const activeNominalField = currencyKey === 'usd' ? 'valor_nominal_a_ser_descontado_usd' : 'valor_nominal_a_ser_descontado_brl';

  if (visible.has('data_de_in_cio_do_faturamento') && isBlank(values.data_de_in_cio_do_faturamento)) {
    values.data_de_in_cio_do_faturamento = defaults.data_de_in_cio_do_faturamento;
  }
  if (visible.has('quantidade_de_parcelas_totais') && isBlank(values.quantidade_de_parcelas_totais)) {
    values.quantidade_de_parcelas_totais = defaults.quantidade_de_parcelas_totais;
  }
  if (visible.has('quantidade') && isBlank(values.quantidade)) {
    values.quantidade = defaults.quantidade;
  }
  if (isBlank(values.afiliados_que_comp_em_a_cobran_a)) {
    values.afiliados_que_comp_em_a_cobran_a = defaults.afiliados_que_comp_em_a_cobran_a;
  }
  if (isBlank(values.id_backoffice_do_afiliado)) {
    values.id_backoffice_do_afiliado = defaults.id_backoffice_do_afiliado;
  }
  if (visible.has(activeSubtotalField) && isBlank(values[activeSubtotalField])) {
    values[activeSubtotalField] = currencyKey === 'usd' ? defaults.usd_amount_default : defaults.brl_amount_default;
  }
  if (isBlank(values[activeTotalField])) {
    values[activeTotalField] = currencyKey === 'usd' ? defaults.usd_amount_default : defaults.brl_amount_default;
  }
  if (visible.has(activeUnitField) && isBlank(values[activeUnitField])) {
    values[activeUnitField] = currencyKey === 'usd' ? defaults.usd_amount_default : defaults.brl_amount_default;
  }
  if (visible.has(activeNominalField) && isBlank(values[activeNominalField])) {
    values[activeNominalField] = currencyKey === 'usd' ? defaults.usd_discount_default : defaults.brl_discount_default;
  }

  for (const fieldId of visible) {
    if (percentLikeFields.has(fieldId) && isBlank(values[fieldId])) {
      values[fieldId] = defaults.percentual_default;
    }
    if (/^valor_do_imposto_a_ser_isento_/.test(fieldId) && isBlank(values[fieldId])) {
      values[fieldId] = defaults.isencao_imposto_default;
    }
  }

  const fieldIds = Array.from(new Set([
    ...Object.keys(values),
    ...visible,
    'afiliados_que_comp_em_a_cobran_a',
    'id_backoffice_do_afiliado',
    activeTotalField,
  ]));

  return fieldIds
    .filter((fieldId) => !fieldId.startsWith('statement_'))
    .filter((fieldId) => !fieldId.startsWith('copy_of_statement_'))
    .filter((fieldId) => fieldId !== noopDateField || !isBlank(values[fieldId]))
    .filter((fieldId) => !isBlank(values[fieldId]))
    .map((fieldId) => ({
      field_id: fieldId,
      field_value: coerceValue(fieldId, values[fieldId]),
    }));
}

const specs = Array.isArray(batch.item_specs) ? batch.item_specs : [];
const varDefs = [];
const mutationParts = [];
const variables = {};

specs.forEach((spec, index) => {
  const alias = `item${index + 1}`;
  const varName = `input${index + 1}`;
  varDefs.push(`$${varName}: CreateCardInput!`);
  mutationParts.push(`${alias}: createCard(input: $${varName}) { card { id title } }`);
  variables[varName] = {
    pipe_id: Number(manifest.constants.fin02_pipe_id),
    title: `TEST FIN-02 ${spec.family_label} ${spec.currency_code} S${spec.scenario_seq_pad} ${runtime.batch_key}`,
    fields_attributes: buildFields(spec),
  };
});

return [{
  json: {
    runtime,
    batch,
    query: `mutation CreateFin02Batch(${varDefs.join(', ')}) { ${mutationParts.join(' ')} }`,
    variables,
  },
}];

const batch = $json.batch || {};
const runtime = $json.runtime || {};
const response = ($json.data && typeof $json.data === 'object' && !Array.isArray($json.data)) ? $json.data : {};
const gqlErrors = Array.isArray($json.errors) ? $json.errors : [];
const createdItems = [];
const missingAliases = [];
const specs = Array.isArray(batch.item_specs) ? batch.item_specs : [];

specs.forEach((spec, index) => {
  const alias = `item${index + 1}`;
  const cardId = response[alias] && response[alias].card && response[alias].card.id != null
    ? String(response[alias].card.id)
    : null;
  if (cardId) {
    createdItems.push({
      item_id: cardId,
      source_scenario_id: spec.source_scenario_id,
      scenario_seq_pad: spec.scenario_seq_pad,
      family_key: spec.family_key,
      currency_key: spec.currency_key,
      item_type_key: spec.item_type_key,
    });
  } else {
    missingAliases.push(alias);
  }
});

const success = gqlErrors.length === 0 && missingAliases.length === 0;
return [{
  json: {
    runtime,
    result: {
      batch_key: batch.batch_key,
      batch_seq: batch.batch_seq,
      batch_seq_pad: batch.batch_seq_pad,
      family_key: batch.family_key,
      family_label: batch.family_label,
      currency_key: batch.currency_key,
      currency_code: batch.currency_code,
      rule_template_key: batch.rule_template_key,
      expected_item_count: specs.length,
      created_items: createdItems,
      created_item_ids: createdItems.map((entry) => entry.item_id),
      status: success ? 'success' : 'failed',
      reason: success ? 'items_created' : 'item_batch_failed',
      gql_errors: gqlErrors,
      missing_aliases: missingAliases,
    },
  },
}];

const sd = $getWorkflowStaticData('global');
const run = sd.finSeedRun || {};
const result = $json.result || {};
if (!Array.isArray(run.itemBatchResults)) run.itemBatchResults = [];
if (!Array.isArray(run.partialCreatedItemIds)) run.partialCreatedItemIds = [];
run.itemBatchResults.push(result);
for (const itemId of (result.created_item_ids || [])) {
  if (!run.partialCreatedItemIds.includes(itemId)) run.partialCreatedItemIds.push(itemId);
}
sd.finSeedRun = run;
return $input.all();

const sd = $getWorkflowStaticData('global');
const run = sd.finSeedRun || {};
const results = Array.isArray(run.itemBatchResults) ? run.itemBatchResults : [];
const readyBatches = [];
const skipped = [];

for (const itemResult of results) {
  if (itemResult && itemResult.status === 'success' && Array.isArray(itemResult.created_item_ids) && itemResult.created_item_ids.length === itemResult.expected_item_count) {
    readyBatches.push({
      batch_key: itemResult.batch_key,
      batch_seq: itemResult.batch_seq,
      batch_seq_pad: itemResult.batch_seq_pad,
      family_key: itemResult.family_key,
      family_label: itemResult.family_label,
      currency_key: itemResult.currency_key,
      currency_code: itemResult.currency_code,
      rule_template_key: itemResult.rule_template_key,
      created_item_ids: itemResult.created_item_ids,
    });
  } else if (itemResult) {
    skipped.push({
      batch_key: itemResult.batch_key,
      family_key: itemResult.family_key,
      currency_key: itemResult.currency_key,
      reason: itemResult.reason || 'item_batch_failed',
    });
  }
}

run.skippedRuleBatches = skipped;
sd.finSeedRun = run;
return [{ json: { rule_batches: readyBatches, skipped_rule_batches: skipped } }];

const sd = $getWorkflowStaticData('global');
const manifest = sd.finSeedManifest || {};
const run = sd.finSeedRun || {};
const batch = $json.batch || {};
const defaults = (manifest.defaults && manifest.defaults.fin01) ? manifest.defaults.fin01 : {};
const coercion = (manifest.coercion && typeof manifest.coercion === 'object') ? manifest.coercion : {};
const arrayFields = new Set(Array.isArray(coercion.fin01_array_fields) ? coercion.fin01_array_fields : []);
const numberFields = new Set(Array.isArray(coercion.fin01_number_fields) ? coercion.fin01_number_fields : []);
const template = (manifest.rule_templates || []).find((entry) => entry.template_key === batch.rule_template_key);
if (!template) {
  throw new Error(`Missing rule template for ${batch.rule_template_key || 'unknown'}`);
}

function toArray(value) {
  if (Array.isArray(value)) return value.map((entry) => String(entry));
  return [String(value)];
}

function coerceValue(fieldId, value) {
  if (arrayFields.has(fieldId)) return toArray(value);
  if (numberFields.has(fieldId)) return Number(value);
  return String(value);
}

const values = {
  ...template.values,
  contatos_que_receber_o_a_fatura: defaults.contatos_que_receber_o_a_fatura,
  forma_de_pagamento: defaults.forma_de_pagamento,
  identificador_fiscal_na_fatura: defaults.identificador_fiscal_na_fatura,
  dia_de_gera_o_da_fatura: defaults.dia_de_gera_o_da_fatura,
  itens_da_fatura: batch.created_item_ids,
};
if (batch.family_key === 'afiliados') values.clientes_na_fatura = defaults.clientes_na_fatura;
if (batch.family_key === 'rede') values.rede_na_fatura = defaults.rede_na_fatura;
if (batch.currency_key === 'brl') values.teto_de_faturamento_brl = defaults.teto_de_faturamento_brl;
if (batch.currency_key === 'usd') values.teto_de_faturamento_usd = defaults.teto_de_faturamento_usd;

const orderedFieldIds = [
  'tipo_de_cliente_final',
  'clientes_na_fatura',
  'rede_na_fatura',
  'contatos_que_receber_o_a_fatura',
  'forma_de_pagamento',
  'itens_da_fatura',
  'moeda_do_teto_de_faturamento',
  'teto_de_faturamento_brl',
  'teto_de_faturamento_usd',
  'identificador_fiscal_na_fatura',
  'dia_de_gera_o_da_fatura',
];

const fields_attributes = orderedFieldIds
  .filter((fieldId) => values[fieldId] !== undefined && values[fieldId] !== null && !(Array.isArray(values[fieldId]) && values[fieldId].length === 0))
  .map((fieldId) => ({ field_id: fieldId, field_value: coerceValue(fieldId, values[fieldId]) }));

return [{
  json: {
    batch,
    rule_title: `TEST FIN-01 ${batch.family_label} ${batch.currency_code} B${batch.batch_seq_pad} ${run.batchKey}`,
    query: 'mutation CreateRule($input: CreateCardInput!) { createRule: createCard(input: $input) { card { id title } } }',
    variables: {
      input: {
        pipe_id: Number(manifest.constants.fin01_pipe_id),
        title: `TEST FIN-01 ${batch.family_label} ${batch.currency_code} B${batch.batch_seq_pad} ${run.batchKey}`,
        fields_attributes,
      },
    },
  },
}];

const batch = $json.batch || {};
const response = ($json.data && typeof $json.data === 'object' && !Array.isArray($json.data)) ? $json.data : {};
const ruleId = response.createRule && response.createRule.card && response.createRule.card.id != null
  ? String(response.createRule.card.id)
  : null;
const gqlErrors = Array.isArray($json.errors) ? $json.errors : [];
const itemIds = Array.isArray(batch.created_item_ids) ? batch.created_item_ids.map((entry) => String(entry)) : [];
const ruleCreated = Boolean(ruleId) && gqlErrors.length === 0;

if (!ruleCreated) {
  return [{
    json: {
      batch,
      rule_id: ruleId,
      rule_created: false,
      rule_response_errors: gqlErrors,
      backfill_aliases: [],
      query: 'query NoopRuleBackfill { __typename }',
      variables: {},
    },
  }];
}

const varDefs = ['$ruleValue: [UndefinedInput!]!'];
const mutationParts = [];
const variables = { ruleValue: [ruleId] };
const aliases = [];
itemIds.forEach((itemId, index) => {
  const itemVar = `itemId${index + 1}`;
  const alias = `backfill${index + 1}`;
  varDefs.push(`$${itemVar}: ID!`);
  mutationParts.push(`${alias}: updateFieldsValues(input: { nodeId: $${itemVar}, values: [{ fieldId: "id_da_regra", value: $ruleValue, operation: REPLACE }] }) { success updatedNode { ... on Card { id } } }`);
  variables[itemVar] = itemId;
  aliases.push(alias);
});

return [{
  json: {
    batch,
    rule_id: ruleId,
    rule_created: true,
    rule_response_errors: [],
    backfill_aliases: aliases,
    query: `mutation BackfillRuleId(${varDefs.join(', ')}) { ${mutationParts.join(' ')} }`,
    variables,
  },
}];

const batch = $json.batch || {};
const ruleId = $json.rule_id ? String($json.rule_id) : null;
const ruleCreated = $json.rule_created === true;
const ruleResponseErrors = Array.isArray($json.rule_response_errors) ? $json.rule_response_errors : [];
const backfillAliases = Array.isArray($json.backfill_aliases) ? $json.backfill_aliases : [];
const backfillResponse = ($json.data && typeof $json.data === 'object' && !Array.isArray($json.data)) ? $json.data : {};
const backfillErrors = Array.isArray($json.errors) ? $json.errors : [];
const failedBackfills = [];

if (ruleCreated) {
  for (const alias of backfillAliases) {
    if (!(backfillResponse[alias] && backfillResponse[alias].success === true)) {
      failedBackfills.push(alias);
    }
  }
}

let status = 'failed';
let reason = 'rule_create_failed';
if (ruleCreated && backfillErrors.length === 0 && failedBackfills.length === 0) {
  status = 'processed';
  reason = 'rule_created_and_backfilled';
} else if (ruleCreated) {
  reason = 'item_backfill_failed';
}

return [{
  json: {
    result: {
      batch_key: batch.batch_key,
      batch_seq: batch.batch_seq,
      batch_seq_pad: batch.batch_seq_pad,
      family_key: batch.family_key,
      family_label: batch.family_label,
      currency_key: batch.currency_key,
      currency_code: batch.currency_code,
      item_count: Array.isArray(batch.created_item_ids) ? batch.created_item_ids.length : 0,
      created_item_ids: Array.isArray(batch.created_item_ids) ? batch.created_item_ids : [],
      rule_id: ruleId,
      status,
      reason,
      rule_response_errors: ruleResponseErrors,
      backfill_errors: backfillErrors,
      failed_backfills: failedBackfills,
    },
  },
}];

const sd = $getWorkflowStaticData('global');
const run = sd.finSeedRun || {};
const result = $json.result || {};
if (!Array.isArray(run.ruleBatchResults)) run.ruleBatchResults = [];
if (!Array.isArray(run.partialCreatedRuleIds)) run.partialCreatedRuleIds = [];
run.ruleBatchResults.push(result);
if (result.rule_id && !run.partialCreatedRuleIds.includes(result.rule_id)) {
  run.partialCreatedRuleIds.push(result.rule_id);
}
sd.finSeedRun = run;
return $input.all();

const sd = $getWorkflowStaticData('global');
const manifest = sd.finSeedManifest || {};
const run = sd.finSeedRun || {};
const processed = Array.isArray(run.ruleBatchResults)
  ? run.ruleBatchResults.filter((entry) => entry && entry.status === 'processed' && entry.rule_id)
  : [];
const wantedKeys = ['afiliados_brl', 'afiliados_usd', 'rede_brl', 'rede_usd'];
const samples = [];
for (const key of wantedKeys) {
  const found = processed.find((entry) => `${entry.family_key}_${entry.currency_key}` === key);
  if (found) samples.push(found);
}
const parts = [];
for (let index = 0; index < samples.length; index += 1) {
  const sample = samples[index];
  const slot = index + 1;
  parts.push(`sampleRule${slot}: card(id: "${sample.rule_id}") { id title fields { field { id } value report_value array_value } }`);
  if (Array.isArray(sample.created_item_ids) && sample.created_item_ids[0]) {
    parts.push(`sampleItem${slot}: card(id: "${sample.created_item_ids[0]}") { id title fields { field { id } value report_value array_value } }`);
  }
}
for (const cardId of (manifest.constants && manifest.constants.db_validation_cards) ? manifest.constants.db_validation_cards : []) {
  parts.push(`db_${cardId}: card(id: "${cardId}") { id title fields { field { id } value report_value array_value } }`);
}
const query = parts.length > 0 ? `query ValidateFinSeed { ${parts.join(' ')} }` : 'query ValidateFinSeedNoop { __typename }';
return [{
  json: {
    validation_targets: {
      sample_batches: samples.map((sample) => ({
        key: `${sample.family_key}_${sample.currency_key}`,
        rule_id: sample.rule_id,
        first_item_id: Array.isArray(sample.created_item_ids) ? (sample.created_item_ids[0] || null) : null,
      })),
      db_cards: (manifest.constants && manifest.constants.db_validation_cards) ? manifest.constants.db_validation_cards : [],
    },
    query,
    variables: {},
  },
}];

const sd = $getWorkflowStaticData('global');
const manifest = sd.finSeedManifest || {};
const run = sd.finSeedRun || {};
if ($json && (Object.prototype.hasOwnProperty.call($json, 'data') || Object.prototype.hasOwnProperty.call($json, 'validation_targets'))) {
  run.validation = {
    targets: $json.validation_targets || null,
    response: {
      data: $json.data || null,
      errors: Array.isArray($json.errors) ? $json.errors : [],
    },
  };
  sd.finSeedRun = run;
}

const itemResults = Array.isArray(run.itemBatchResults) ? run.itemBatchResults : [];
const ruleResults = Array.isArray(run.ruleBatchResults) ? run.ruleBatchResults : [];
const unique = (values) => Array.from(new Set((values || []).filter(Boolean)));
const createdItemIds = unique(itemResults.flatMap((entry) => Array.isArray(entry.created_item_ids) ? entry.created_item_ids : []));
const createdRuleIds = unique(ruleResults.map((entry) => entry.rule_id));
const processedRuleIds = unique(ruleResults.filter((entry) => entry.status === 'processed').map((entry) => entry.rule_id));
const failedItemBatches = itemResults.filter((entry) => entry.status !== 'success');
const failedRuleBatches = ruleResults.filter((entry) => entry.status !== 'processed');

let validationSummary = {
  available: false,
  sample_batches_covered: 0,
  db_cards_checked: 0,
  db_rule_link_checks: [],
};

if (run.validation && run.validation.response && run.validation.response.data) {
  const data = run.validation.response.data;
  const targets = run.validation.targets || {};
  const sampleBatches = Array.isArray(targets.sample_batches) ? targets.sample_batches : [];
  const dbCards = Array.isArray(targets.db_cards) ? targets.db_cards : [];
  const ruleIdsByFamily = {};
  for (const sample of sampleBatches) {
    const key = String(sample.key || '');
    if (key.startsWith('afiliados_') && sample.rule_id) ruleIdsByFamily.afiliados = sample.rule_id;
    if (key.startsWith('rede_') && sample.rule_id) ruleIdsByFamily.rede = sample.rule_id;
  }
  const checks = [];
  for (const cardId of dbCards) {
    const alias = `db_${cardId}`;
    const card = data[alias];
    const fields = card && Array.isArray(card.fields) ? card.fields : [];
    const linkField = fields.find((entry) => entry && entry.field && entry.field.id === 'regras_de_faturamento');
    const arrayValue = Array.isArray(linkField && linkField.array_value) ? linkField.array_value.map((value) => String(value)) : [];
    const expectedRuleId = (String(cardId) === '1259910277' || String(cardId) === '1284069901')
      ? ruleIdsByFamily.afiliados
      : ruleIdsByFamily.rede;
    checks.push({
      card_id: String(cardId),
      expected_rule_id: expectedRuleId || null,
      contains_expected_rule: expectedRuleId ? arrayValue.includes(String(expectedRuleId)) : false,
    });
  }
  validationSummary = {
    available: true,
    sample_batches_covered: sampleBatches.length,
    db_cards_checked: dbCards.length,
    db_rule_link_checks: checks,
  };
}

return [{
